{"content":"1: import { omitBy, isNil, isNumber, defaultTo, groupBy, omit } from 'lodash';
2: 
3: import {
4:   PanelModel,
5:   FieldMatcherID,
6:   ConfigOverrideRule,
7:   ThresholdsMode,
8:   ThresholdsConfig,
9:   FieldConfig,
10:   DataFrame,
11:   FieldType,
12:   ByNamesMatcherMode,
13: } from '@grafana/data';
14: import { ReduceTransformerOptions } from '@grafana/data/internal';
15: 
16: import { Options } from './panelcfg.gen';
17: 
18: /**
19:  * At 7.0, the `table` panel was swapped from an angular implementation to a react one.
20:  * The models do not match, so this process will delegate to the old implementation when
21:  * a saved table configuration exists.
22:  */
23: export const tableMigrationHandler = (panel: PanelModel<Options>): Partial<Options> => {
24:   // Table was saved as an angular table, lets just swap to the 'table-old' panel
25:   if (!panel.pluginVersion && 'columns' in panel) {
26:     console.log('Was angular table', panel);
27:   }
28: 
29:   migrateTextWrapToFieldLevel(panel);
30:   migrateHiddenFields(panel);
31:   migrateFooterV2(panel);
32: 
33:   // Nothing changed
34:   return panel.options;
35: };
36: 
37: const transformsMap = {
38:   timeseries_to_rows: 'seriesToRows',
39:   timeseries_to_columns: 'seriesToColumns',
40:   timeseries_aggregations: 'reduce',
41:   table: 'merge',
42: };
43: 
44: const columnsMap = {
45:   avg: 'mean',
46:   min: 'min',
47:   max: 'max',
48:   total: 'sum',
49:   current: 'lastNotNull',
50:   count: 'count',
51: };
52: 
53: const colorModeMap = {
54:   cell: 'color-background',
55:   row: 'color-background',
56:   value: 'color-text',
57: };
58: 
59: type Transformations = keyof typeof transformsMap;
60: 
61: type Transformation = {
62:   id: string;
63:   options: ReduceTransformerOptions;
64: };
65: 
66: type Columns = keyof typeof columnsMap;
67: 
68: type Column = {
69:   value: Columns;
70:   text: string;
71: };
72: 
73: type ColorModes = keyof typeof colorModeMap;
74: 
75: const generateThresholds = (thresholds: string[], colors: string[]) => {
76:   return [-Infinity, ...thresholds].map((threshold, idx) => ({
77:     color: colors[idx],
78:     value: isNumber(threshold) ? threshold : parseInt(threshold, 10),
79:   }));
80: };
81: 
82: const migrateTransformations = (
83:   panel: PanelModel<Partial<Options>>,
84:   oldOpts: { columns: any; transform: Transformations }
85: ) => {
86:   const transformations: Transformation[] = panel.transformations ?? [];
87:   if (Object.keys(transformsMap).includes(oldOpts.transform)) {
88:     const opts: ReduceTransformerOptions = {
89:       reducers: [],
90:     };
91:     if (oldOpts.transform === 'timeseries_aggregations') {
92:       opts.includeTimeField = false;
93:       opts.reducers = oldOpts.columns.map((column: Column) => columnsMap[column.value]);
94:     }
95:     transformations.push({
96:       id: transformsMap[oldOpts.transform],
97:       options: opts,
98:     });
99:   }
100:   return transformations;
101: };
102: 
103: type Style = {
104:   unit: string;
105:   type: string;
106:   alias: string;
107:   decimals: number;
108:   colors: string[];
109:   colorMode: ColorModes;
110:   pattern: string;
111:   thresholds: string[];
112:   align?: string;
113:   dateFormat: string;
114:   link: boolean;
115:   linkTargetBlank?: boolean;
116:   linkTooltip?: string;
117:   linkUrl?: string;
118: };
119: 
120: const migrateTableStyleToOverride = (style: Style) => {
121:   const fieldMatcherId = /^\/.*\/$/.test(style.pattern) ? FieldMatcherID.byRegexp : FieldMatcherID.byName;
122:   const override: ConfigOverrideRule = {
123:     matcher: {
124:       id: fieldMatcherId,
125:       options: style.pattern,
126:     },
127:     properties: [],
128:   };
129: 
130:   if (style.alias) {
131:     override.properties.push({
132:       id: 'displayName',
133:       value: style.alias,
134:     });
135:   }
136: 
137:   if (style.unit) {
138:     override.properties.push({
139:       id: 'unit',
140:       value: style.unit,
141:     });
142:   }
143: 
144:   if (style.decimals !== undefined) {
145:     override.properties.push({
146:       id: 'decimals',
147:       value: style.decimals,
148:     });
149:   }
150: 
151:   if (style.type === 'date') {
152:     override.properties.push({
153:       id: 'unit',
154:       value: `time: ${style.dateFormat}`,
155:     });
156:   }
157: 
158:   if (style.type === 'hidden') {
159:     override.properties.push({
160:       id: 'custom.hidden',
161:       value: true,
162:     });
163:   }
164: 
165:   if (style.link) {
166:     override.properties.push({
167:       id: 'links',
168:       value: [
169:         {
170:           title: defaultTo(style.linkTooltip, ''),
171:           url: defaultTo(style.linkUrl, ''),
172:           targetBlank: defaultTo(style.linkTargetBlank, false),
173:         },
174:       ],
175:     });
176:   }
177: 
178:   if (style.colorMode) {
179:     override.properties.push({
180:       id: 'custom.cellOptions',
181:       value: {
182:         type: colorModeMap[style.colorMode],
183:       },
184:     });
185:   }
186: 
187:   if (style.align) {
188:     override.properties.push({
189:       id: 'custom.align',
190:       value: style.align === 'auto' ? null : style.align,
191:     });
192:   }
193: 
194:   if (style.thresholds?.length && style.colors?.length) {
195:     override.properties.push({
196:       id: 'thresholds',
197:       value: {
198:         mode: ThresholdsMode.Absolute,
199:         steps: generateThresholds(style.thresholds, style.colors),
200:       },
201:     });
202:   }
203: 
204:   return override;
205: };
206: 
207: const migrateDefaults = (prevDefaults: Style) => {
208:   let defaults: FieldConfig = {
209:     custom: {},
210:   };
211:   if (prevDefaults) {
212:     defaults = omitBy(
213:       {
214:         unit: prevDefaults.unit,
215:         decimals: prevDefaults.decimals,
216:         displayName: prevDefaults.alias,
217:         custom: {
218:           align: prevDefaults.align === 'auto' ? null : prevDefaults.align,
219:         },
220:       },
221:       isNil
222:     );
223: 
224:     if (prevDefaults.thresholds && prevDefaults.thresholds.length) {
225:       const thresholds: ThresholdsConfig = {
226:         mode: ThresholdsMode.Absolute,
227:         steps: generateThresholds(prevDefaults.thresholds, prevDefaults.colors),
228:       };
229:       defaults.thresholds = thresholds;
230:     }
231: 
232:     if (prevDefaults.colorMode) {
233:       defaults.custom.cellOptions = {
234:         type: colorModeMap[prevDefaults.colorMode],
235:       };
236:     }
237:   }
238:   return defaults;
239: };
240: 
241: /**
242:  * This is called when the panel changes from another panel
243:  */
244: export const tablePanelChangedHandler = (
245:   panel: PanelModel<Partial<Options>>,
246:   prevPluginId: string,
247:   prevOptions: any
248: ) => {
249:   // Changing from angular table panel
250:   if (prevPluginId === 'table-old' && prevOptions.angular) {
251:     const oldOpts = prevOptions.angular;
252:     const transformations = migrateTransformations(panel, oldOpts);
253:     const prevDefaults = oldOpts.styles.find((style: any) => style.pattern === '/.*/');
254:     const defaults = migrateDefaults(prevDefaults);
255:     const overrides = oldOpts.styles.filter((style: any) => style.pattern !== '/.*/').map(migrateTableStyleToOverride);
256: 
257:     panel.transformations = transformations;
258:     panel.fieldConfig = {
259:       defaults,
260:       overrides,
261:     };
262:   }
263: 
264:   return {};
265: };
266: 
267: const getMainFrames = (frames: DataFrame[] | null) => {
268:   return frames?.filter((df) => df.meta?.custom?.parentRowIndex === undefined) || [frames?.[0]];
269: };
270: 
271: /**
272:  * In 9.3 meta.custom.parentRowIndex was introduced to support sub-tables.
273:  * In 10.2 meta.custom.parentRowIndex was deprecated in favor of FieldType.nestedFrames, which supports multiple nested frames.
274:  * Migrate DataFrame[] from using meta.custom.parentRowIndex to using FieldType.nestedFrames
275:  */
276: export const migrateFromParentRowIndexToNestedFrames = (frames: DataFrame[] | null) => {
277:   const migratedFrames: DataFrame[] = [];
278:   const mainFrames = getMainFrames(frames).filter(
279:     (frame: DataFrame | undefined): frame is DataFrame => !!frame && frame.length !== 0
280:   );
281: 
282:   mainFrames?.forEach((frame) => {
283:     const subFrames = frames?.filter((df) => frame.refId === df.refId && df.meta?.custom?.parentRowIndex !== undefined);
284:     const subFramesGrouped = groupBy(subFrames, (frame: DataFrame) => frame.meta?.custom?.parentRowIndex);
285:     const subFramesByIndex = Object.keys(subFramesGrouped).map((key) => subFramesGrouped[key]);
286:     const migratedFrame = { ...frame };
287: 
288:     if (subFrames && subFrames.length > 0) {
289:       migratedFrame.fields.push({
290:         name: 'nested',
291:         type: FieldType.nestedFrames,
292:         config: {},
293:         values: subFramesByIndex,
294:       });
295:     }
296:     migratedFrames.push(migratedFrame);
297:   });
298: 
299:   return migratedFrames;
300: };
301: 
302: export const hasDeprecatedParentRowIndex = (frames: DataFrame[] | null) => {
303:   return frames?.some((df) => df.meta?.custom?.parentRowIndex !== undefined);
304: };
305: 
306: export const migrateTextWrapToFieldLevel = (panel: PanelModel<Partial<Options>>) => {
307:   if (panel.fieldConfig?.defaults.custom?.wrapText !== undefined) {
308:     // already migrated
309:     return;
310:   }
311: 
312:   const legacyDefaultWrapText: boolean | undefined = panel.fieldConfig?.defaults.custom?.cellOptions?.wrapText;
313: 
314:   panel.fieldConfig.overrides = panel.fieldConfig.overrides.map((override) => {
315:     if (override.properties) {
316:       override.properties = override.properties.flatMap((property) => {
317:         if (property.id === 'custom.cellOptions' && property.value && property.value.wrapText !== undefined) {
318:           return [
319:             { ...property, value: { ...omit(property.value, 'wrapText') } },
320:             { id: 'custom.wrapText', value: property.value.wrapText },
321:           ];
322:         }
323:         return [property];
324:       });
325:     }
326:     return override;
327:   });
328: 
329:   panel.fieldConfig.defaults.custom = panel.fieldConfig.defaults.custom ?? {};
330:   panel.fieldConfig.defaults.custom.wrapText = legacyDefaultWrapText;
331:   delete panel.fieldConfig.defaults.custom.cellOptions?.wrapText;
332: 
333:   return panel;
334: };
335: 
336: export const migrateHiddenFields = (panel: PanelModel<Partial<Options>>) => {
337:   panel.fieldConfig.overrides = panel.fieldConfig.overrides.map((override) => {
