360: export const migrateFooterV2 = (panel: PanelModel<Options>) => {
361:   if (panel.options && 'footer' in panel.options) {
362:     // we need to cast the footer to the old type to work with it here.
363:     // eslint-disable-next-line @typescript-eslint/consistent-type-assertions
364:     const oldFooter = panel.options.footer as LegacyTableFooterOptions;
365: 
366:     if (oldFooter.show) {
367:       const reducers = oldFooter.reducer;
368: 
369:       panel.fieldConfig.defaults.custom = {
370:         ...panel.fieldConfig.defaults.custom,
371:         footer: {
372:           reducers: reducers,
373:         },
374:       };
375: 
376:       if (oldFooter.countRows && reducers[0] === 'count') {
377:         panel.fieldConfig.defaults.custom.footer.reducers = ['countAll'];
378:       } else if (oldFooter.fields && oldFooter.fields.length > 1) {
379:         delete panel.fieldConfig.defaults.custom.footer;
380: 
381:         // Fields is an array of field names, so push a byNames matcher
382:         // on with the matched reducer.
383:         panel.fieldConfig.overrides.push({
384:           matcher: {
385:             id: FieldMatcherID.byNames,
386:             options: {
387:               mode: ByNamesMatcherMode.include,
388:               names: oldFooter.fields,
389:             },
390:           },
391:           properties: [{ id: 'custom.footer.reducers', value: reducers }],
392:         });
393:       } else if (oldFooter.fields && oldFooter.fields.length === 1) {
394:         delete panel.fieldConfig.defaults.custom.footer;
395: 
396:         // Single field, so we can use a byName matcher
397:         panel.fieldConfig.overrides.push({
398:           matcher: {
399:             id: FieldMatcherID.byName,
400:             options: oldFooter.fields[0],
401:           },
402:           properties: [{ id: 'custom.footer.reducers', value: reducers }],
403:         });
404:       }
405:     }
406: 
407:     if (oldFooter.enablePagination != null) {
408:       panel.options.enablePagination = oldFooter.enablePagination;
409:     }
410: 
411:     delete panel.options.footer;
412:   }
413: };
