34: export function getPanelOptionsWithDefaults({
35:   plugin,
36:   currentOptions,
37:   currentFieldConfig,
38:   isAfterPluginChange,
39: }: Props): OptionDefaults {
40:   const optionsWithDefaults = mergeWith({}, plugin.defaults, currentOptions || {}, (objValue, srcValue) => {
41:     if (isArray(srcValue)) {
42:       return srcValue;
43:     }
44:     return;
45:   });
46: 
47:   const fieldConfigWithDefaults = applyFieldConfigDefaults(currentFieldConfig, plugin);
48:   const fieldConfigWithOptimalColorMode = adaptFieldColorMode(plugin, fieldConfigWithDefaults, isAfterPluginChange);
49: 
50:   return { options: optionsWithDefaults, fieldConfig: fieldConfigWithOptimalColorMode };
51: }
