112: function cleanProperties(obj: object, parentPath: string, fieldConfigRegistry: FieldConfigOptionsRegistry) {
113:   let found = false;
114: 
115:   for (const [propName, value] of Object.entries(obj)) {
116:     const fullPath = `${parentPath}${propName}`;
117:     const existsInRegistry = !!fieldConfigRegistry.getIfExists(fullPath);
118: 
119:     // need to check early here as some standard properties have nested properies
120:     if (existsInRegistry) {
121:       found = true;
122:       continue;
123:     }
124: 
125:     if (isArray(value) || !isObject(value)) {
126:       if (!existsInRegistry) {
127:         unset(obj, propName);
128:       }
129:     } else {
130:       const childPropFound = cleanProperties(value, `${fullPath}.`, fieldConfigRegistry);
131:       // If no child props found unset the main object
132:       if (!childPropFound) {
133:         unset(obj, propName);
134:       }
135:     }
136:   }
137: 
138:   return found;
139: }
