141: function adaptFieldColorMode(
142:   plugin: PanelPlugin,
143:   fieldConfig: FieldConfigSource,
144:   isAfterPluginChange: boolean
145: ): FieldConfigSource {
146:   if (!isAfterPluginChange) {
147:     return fieldConfig;
148:   }
149: 
150:   // adjust to prefered field color setting if needed
151:   const color = plugin.fieldConfigRegistry.getIfExists(FieldConfigProperty.Color);
152: 
153:   if (color && color.settings) {
154:     const colorSettings: FieldColorConfigSettings = color.settings;
155:     const mode = fieldColorModeRegistry.getIfExists(fieldConfig.defaults.color?.mode);
156: 
157:     // When no support fo value colors, use classic palette
158:     if (!colorSettings.byValueSupport) {
159:       if (!mode || mode.isByValue) {
160:         fieldConfig.defaults.color = { mode: FieldColorModeId.PaletteClassic };
161:         return fieldConfig;
162:       }
163:     }
164: 
165:     // When supporting value colors and prefering thresholds, use Thresholds mode.
166:     // Otherwise keep current mode
167:     if (colorSettings.byValueSupport && colorSettings.preferThresholdsMode && mode?.id !== FieldColorModeId.Fixed) {
168:       if (!mode || !mode.isByValue) {
169:         fieldConfig.defaults.color = { mode: FieldColorModeId.Thresholds };
170:         return fieldConfig;
171:       }
172:     }
173: 
174:     // If panel support bySeries then we should default to that when switching to this panel as that is most likely
175:     // what users will expect. Example scenario a user who has a graph panel (time series) and switches to Gauge and
176:     // then back to time series we want the graph panel color mode to reset to classic palette and not preserve the
177:     // Gauge prefered thresholds mode.
178:     if (colorSettings.bySeriesSupport && mode?.isByValue) {
179:       fieldConfig.defaults.color = { mode: FieldColorModeId.PaletteClassic };
180:       return fieldConfig;
181:     }
182:   }
183:   return fieldConfig;
184: }
