204: export function restoreCustomOverrideRules(current: FieldConfigSource, old: FieldConfigSource): FieldConfigSource {
205:   const result = {
206:     defaults: {
207:       ...current.defaults,
208:       custom: old.defaults.custom,
209:     },
210:     overrides: [...current.overrides],
211:   };
212: 
213:   for (const override of old.overrides) {
214:     for (const prop of override.properties) {
215:       if (isCustomFieldProp(prop)) {
216:         const currentOverride = result.overrides.find((o) => isEqual(o.matcher, override.matcher));
217:         if (currentOverride) {
218:           if (currentOverride !== override) {
219:             currentOverride.properties.push(prop);
220:           }
221:         } else {
222:           result.overrides.push(override);
223:         }
224:       }
225:     }
226:   }
227: 
228:   return result;
229: }
